        "id": "ai_rich_text_strategy",
        "type": "rich_text",
        "variant": "default",
        "props": {
          "eyebrow": "Smart Strategy",
          "heading": "Validate Location Demand First",
          "body": {
            "version": 1,
            "nodes": [
              {
                "type": "paragraph",
                "text": "For new vending operators, the order of operations matters. It is essential to validate location demand before investing capital into purchasing machines."
              },
              {
                "type": "paragraph",
                "text": "Securing a high-demand location first ensures that once your machine arrives, you already have active foot traffic ready to purchase. Analyzing environmental signals is key to predicting your site's profitability."
              }
            ]
          }
        }
      },
      "sourceDocumentIds": [
        "11111111-1111-4111-8111-111111111111"
      ],
