    {
      "block": {
        "id": "ai_card_grid_signals",
        "type": "card_grid",
        "variant": "standard",
        "props": {
          "heading": "The Key Indicators of Vending Demand",
          "cards": [
            {
              "title": "Foot Traffic",
              "body": "Measure the sheer volume of prospective customers walking past your desired machine placement area daily.",
              "href": "/start-vending/foot-traffic"
            },
            {
              "title": "Dwell Time",
              "body": "Look for environments where people naturally linger or wait, creating a higher window of opportunity for an impulse buy.",
              "href": "/start-vending/dwell-time"
            },
            {
              "title": "Existing Food Options",
              "body": "Review surrounding competition. Locations with fewer quick snack alternatives usually generate higher vending sales.",
              "href": "/start-vending/competition"
            }
          ]
        }
      },
      "sourceDocumentIds": [
        "11111111-1111-4111-8111-111111111111"
