    {
      "block": {
        "id": "ai_faq_vending_basics",
        "type": "faq",
        "variant": "accordion",
        "props": {
          "heading": "Frequently Asked Questions",
          "items": [
            {
              "question": "Should I purchase my vending machines first?",
              "answer": "No, new operators should validate demand at their target locations before buying any vending machines."
            },
            {
              "question": "What indicators suggest a prime location for vending?",
              "answer": "The strongest signals of demand at any location are high foot traffic, longer dwell times, and a scarcity of other existing food options."
            }
          ]
        }
      },
